arguments.command:
# Check the public API surface of the key packages
cd /tmp/sv-39b5acbad6cb47cf9d65a3a0fc250c3b/ResearchAgent

# Create a quick script to list types
cat > /tmp/list_types.cs << 'SCRIPT'
using System.Reflection;

var asmPaths = new[] {
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/microsoft.agents.ai/1.6.2/lib/net10.0/Microsoft.Agents.AI.dll"),
    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/microsoft.agents.ai.abstractions/1.6.2/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll"),
};

foreach (var p in asmPaths)
{
    if (!File.Exists(p)) { Console.WriteLine($"NOT FOUND: {p}"); continue; }
    var asm = Assembly.LoadFrom(p);
    Console.WriteLine($"\n=== {Path.GetFileName(p)} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        Console.WriteLine($"  {t.FullName}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly).OrderBy(m => m.Name))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
