arguments.command:
# Use reflection via a temp project
cd /tmp && mkdir -p TypeExplorer && cat > TypeExplorer/TypeExplorer.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <TargetFramework>net10.0</TargetFramework>
    <OutputType>Exe</OutputType>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="Microsoft.Agents.AI" Version="1.*-*" />
    <PackageReference Include="Microsoft.Extensions.AI" Version="10.*" />
  </ItemGroup>
</Project>
EOF

cat > TypeExplorer/Program.cs << 'CSHARP'
using System.Reflection;

var assemblies = AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.FullName != null && (a.FullName.Contains("Agents.AI") || a.FullName.Contains("Extensions.AI")))
    .OrderBy(a => a.FullName);

// Also load them explicitly
var basePath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages");
var toLoad = new[] {
    "microsoft.agents.ai/1.6.2/lib/net10.0/Microsoft.Agents.AI.dll",
    "microsoft.agents.ai.abstractions/1.6.2/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll",
};

foreach (var rel in toLoad)
{
    var full = Path.Combine(basePath, rel);
    if (File.Exists(full))
    {
        try { Assembly.LoadFrom(full); } catch {}
    }
}

assemblies = AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.FullName != null && a.FullName.Contains("Agents.AI"))
    .OrderBy(a => a.FullName);

foreach (var asm in assemblies)
{
    Console.WriteLine($"\n=== {asm.GetName().Name} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        var baseStr = t.BaseType != null && t.BaseType != typeof(object) ? $" : {t.BaseType.Name}" : "";
        var ifaces = t.GetInterfaces().Select(i => i.Name);
        Console.WriteLine($"  {(t.IsInterface ? "interface" : t.IsEnum ? "enum" : t.IsAbstract ? "abstract class" : "class")} {t.FullName}{baseStr}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly).Take(15).OrderBy(m => m.Name))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
CSHARP

