/// <summary>
/// Provides web-search and note-taking tools that the research agent can call.
/// </summary>
static class ResearchTools
{
    private static readonly List<string> s_notes = [];
    private static readonly HttpClient s_http = new();

    /// <summary>Searches the web for a query and returns a page of results.</summary>
    [Description("Searches the web for a query and returns relevant results. Use this to gather information about a topic.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Use DuckDuckGo's instant-answer API (no key required).
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";

        try
        {
            var json = await s_http.GetStringAsync(url);
            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var parts = new List<string>();

            // Abstract / summary
            var abstractText = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                parts.Add($"Summary: {abstractText} (source: {root.GetProperty("AbstractSource").GetString()})");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        parts.Add($"- {text}");
                }
            }

            if (parts.Count == 0)
                parts.Add("No detailed results found. Try rephrasing the query.");

            return string.Join("\n", parts);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    /// <summary>Saves a research note for later use in the summary.</summary>
    [Description("Saves a research note. Use this to record key findings as you research. Each note should capture one important fact or insight.")]
    public static string SaveNote(
        [Description("The content of the note to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝 Note #{s_notes.Count} saved");
        return $"Note #{s_notes.Count} saved successfully.";
    }

    /// <summary>Returns all notes taken so far.</summary>
    [Description("Retrieves all notes saved so far. Use this to review your findings before writing a summary.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", s_notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

